import numpy as np

def weighted_random_sampler(weights: np.ndarray, n_samples: int) -> np.ndarray:
    weights = np.asarray(weights, dtype=np.float64)
    if np.any(weights < 0):
        raise ValueError('All weights must be non-negative')
    probs = weights / weights.sum()
    return np.random.choice(len(weights), size=n_samples, replace=True, p=probs)

def class_weight_sampler(y: np.ndarray) -> np.ndarray:
    y = np.asarray(y)
    classes, counts = np.unique(y, return_counts=True)
    class_weights = 1.0 / counts
    weight_map = {c: w for c, w in zip(classes, class_weights)}
    return np.array([weight_map[label] for label in y])

